# DiskStation Monitor — Fix frontend TypeScript errors
# Run: Set-ExecutionPolicy Bypass -Scope Process -Force; .\TSFIX.ps1

$RepoPath = "C:\Users\LionelMosley\Documents\HTML\Synology - DiskStation Monitor"
Set-Location $RepoPath
Write-Host "Applying frontend TypeScript fix..." -ForegroundColor Cyan

# frontend/src/main.ts
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$fullPath = Join-Path $RepoPath "frontend/src/main.ts"
$dir = Split-Path $fullPath -Parent
if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
[System.IO.File]::WriteAllBytes($fullPath, $bytes)
Write-Host "  wrote frontend/src/main.ts" -ForegroundColor Green

git add frontend/src/main.ts
git commit -m "fix: resolve all TypeScript errors in frontend main.ts"
git push origin main

if ($LASTEXITCODE -eq 0) {
    Write-Host "`n✅ Pushed! Netlify is rebuilding the frontend." -ForegroundColor Green
    Write-Host "   https://app.netlify.com/projects/diskstation-monitor/deploys" -ForegroundColor Cyan
} else {
    Write-Host "`n❌ Push failed." -ForegroundColor Red
}